/**
 * Onboarding Engine — 新用戶引導內容
 * 當用戶沒有發票或發票 < 10 張時，AI 管家變身為教學管家
 */

export const NEW_USER_THRESHOLD = 10;

export function isNewUser(invoiceCount) {
  return !invoiceCount || invoiceCount < NEW_USER_THRESHOLD;
}

